from flask import Flask, request, jsonify
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import os

app = Flask(__name__)

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, email TEXT UNIQUE, password TEXT)''')
    c.execute('''CREATE TABLE IF NOT EXISTS password_resets
                 (id INTEGER PRIMARY KEY, email TEXT, token TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    conn.commit()
    conn.close()

# Send reset email
def send_reset_email(email, token):
    # In production, use proper email configuration
    reset_link = f"http://localhost:5000/reset/{token}"
    # Simulate email sending
    print(f"Reset link sent to {email}: {reset_link}")

@app.route('/request_reset', methods=['POST'])
def request_reset():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    # Generate random token
    token = secrets.token_urlsafe(32)
    
    # Store token in database
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    
    try:
        c.execute("INSERT INTO password_resets (email, token) VALUES (?, ?)", (email, token))
        conn.commit()
        send_reset_email(email, token)
        return jsonify({'message': 'Reset link sent'})
    except sqlite3.IntegrityError:
        return jsonify({'error': 'User not found'}), 404
    finally:
        conn.close()

@app.route('/reset/<token>', methods=['POST'])
def reset_password(token):
    data = request.get_json()
    new_password = data.get('password')
    
    if not new_password:
        return jsonify({'error': 'Password is required'}), 400
    
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    
    try:
        c.execute("SELECT email FROM password_resets WHERE token = ?", (token,))
        result = c.fetchone()
        
        if not result:
            return jsonify({'error': 'Invalid token'}), 400
        
        email = result[0]
        # Update user password (simplified)
        c.execute("UPDATE users SET password = ? WHERE email = ?", (new_password, email))
        c.execute("DELETE FROM password_resets WHERE token = ?", (token,))
        conn.commit()
        return jsonify({'message': 'Password reset successfully'})
    except Exception as e:
        return jsonify({'error': 'Failed to reset password'}), 500
    finally:
        conn.close()

if __name__ == '__main__':
    init_db()
